window.I18N.es = {"_label": "Español", "404": {"meta": {"title": "Página no encontrada — Textopia", "desc": "El hilo que buscas se ha soltado, pero la historia sigue tejiéndose."}, "h1": "Parece que esta página se ha deshilachado", "msg": "El hilo que buscas no está aquí, pero la historia sigue tejiéndose.", "home": "Volver al inicio", "cta": "Lee el capítulo 1 gratis", "imgAlt": "Yiseo remendando una página rota"}, "common": {"nav": {"world": "Mundo", "book": "Los libros", "news": "Novedades", "about": "Nosotros", "read": "Lee el capítulo 1 — Gratis"}, "bottom": {"world": "Mundo", "book": "Libros", "read": "Cap. 1 gratis", "quiz": "Test"}, "drawer": {"brand": "Textopia", "home": "Inicio", "read": "Lee el capítulo 1 — Gratis", "quiz": "Encuentra tu prenda compañera", "world": "Mundo · Mapa del continente", "book": "Sobre los libros", "store": "Tienda", "news": "Novedades", "about": "Nuestra historia", "theme": "Apariencia", "terms": "Términos de uso", "privacy": "Política de privacidad", "menuOpen": "Abrir menú", "close": "Cerrar", "langLabel": "Idioma"}, "footer": {"brandDesc": "Un mundo donde la ropa respira. Una segunda historia para lo que fue desechado.", "exploreH": "Explorar", "world": "Mundo", "read": "Capítulo 1 gratis", "quiz": "Encuentra tu prenda", "store": "Tienda", "policyH": "Términos y políticas", "terms": "Términos de uso", "privacy": "Política de privacidad", "faq": "Preguntas frecuentes", "biz": "Seam Press es una marca editorial de Orsion · Orsion · CEO Kwon Taek-jun · Reg. mercantil n.º 609-35-66228<br>#1901-50, 143 Dongtan-gambaesan-ro, Dongtan, Hwaseong, Gyeonggi, Corea · Contacto neocomix@neocomix.com · registro de comercio electrónico en trámite", "bottom": "© 2026 Orsion. ¿Tu ropa es feliz hoy?"}, "news": {"emailPh": "Correo electrónico", "subscribe": "Suscribirse", "errFormat": "Eso no parece un correo válido", "already": "Ya estás con nosotros", "ok": "El hilo quedó atado. Solo te escribiremos, con delicadeza, cuando haya buenas noticias.", "fail": "El hilo se soltó por un momento. Inténtalo de nuevo en un ratito.", "done": "Listo"}}, "index": {"meta": {"title": "Textopia — Tu ropa está viva", "desc": "Textopia, una acogedora fantasía sanadora donde la ropa vive y respira. Acompaña a Yiseo, una zurcidora que cose de nuevo un mundo roto. Lee el capítulo 1 gratis."}, "hero": {"act1": "Tu ropa está…", "alive": "viva.", "act3": "Un solo hilo abrió un mundo.", "scroll": "DESLIZA", "skip": "Saltar la intro ↓", "h1": "Un mundo de ropa desechada:<br>Textopia", "sub": "Yiseo, una zurcidora, cae en este mundo —<br>y con una sola aguja, empieza a coserlo de nuevo.", "cta": "Lee el capítulo 1 — Gratis", "mapHint": "🪡 Toca una tierra para explorarla", "hrMore": "Descubre más en Mundo →"}, "region": {"knit": "Montaña de Punto", "denim": "Cañón Denim", "silk": "Océano de Seda", "leather": "Selva de Cuero", "cotton": "Ciudad Algodón", "grave": "Tumba de Harapos"}, "regionDesc": {"cotton": "El corazón del continente: una ciudad de algodón sencillo, hogar de la pequeña tienda de Yiseo, 'Una Puntada'.", "knit": "Cumbres nevadas tejidas con hilo, donde gira la Rueda del Destino.", "denim": "Un cañón áspero pero leal, hogar del Lago Índigo y la tribu Denim.", "silk": "Un mar que cambia de color con la luz, donde flota el Castillo Capullo.", "leather": "Una selva sureña, dura y frondosa; solo la cruzan quienes atraviesan la Ciénaga del Curtido.", "grave": "La última tierra donde reposa la ropa desechada, y donde comenzó la historia."}, "books": {"h2": "Una historia completa, en tres volúmenes", "sub": "Sin esperar entregas semanales: de principio a fin.", "v1t": "Un destino que va<br>más allá del remiendo", "v1n": "Libro 1", "v1s": "Un mundo extraño, la primera puntada", "v2t": "La sombra de la<br>Puntada de Hierro", "v2n": "Libro 2", "v2s": "La guerra con la Torre de la Aguja", "v3t": "La última<br>puntada", "v3n": "Libro 3", "v3s": "El remiendo más grande de todos"}, "worldTeaser": {"h2": "Esto es Textopia: un continente donde la ropa respira", "sub": "Seis tierras, seis telas. Toca donde te dé curiosidad.", "cta": "Explorar el continente →"}, "match": {"tag": "TEXTOPIA MATCH", "h2": "En Textopia, ¿cuál es tu prenda compañera?", "sub": "Seis preguntas para encontrar tu tela. Basta con un minuto.", "cta": "Encuentra tu prenda del destino"}, "quotesH": "Una puntada entre sus páginas", "quotes": [["“La ropa también lo sabe: quién la cuida y quién la ve como mera herramienta.”", "del Libro 1"], ["“Tranquila. Yo remendaré lo que está roto. Esto no es una cicatriz: es un respiro para volver a vivir.”", "del Libro 1"], ["“¿Qué clase de tienda le da la espalda a un paciente que la necesita?”", "del Libro 1"], ["“La fuerza nunca podrá vencer a la suavidad, y menos aún en la moda.”", "del Libro 3"], ["“No fue culpa tuya. Solo te tocó una sastra un poquito torpe.”", "del Libro 1"], ["La seda se acaba en cuanto se rasga; el algodón solo se hace más fuerte cuanto más lo remiendan.", "del Libro 3"], ["“La mancha no se irá. Pero esa mancha es la prueba misma de que estuvimos vivos.”", "del Libro 3"], ["“¿Tu ropa es feliz hoy?”", "del capítulo final"]], "story": {"h2": "Dos personas fundamos una editorial. Tres, contando a la IA.", "sub": "Una que programa y otra que confecciona ropa, contando historias juntas: una pequeña editorial llamada Seam.", "link": "Nuestra historia →"}, "news": {"h2": "Te avisaremos cuando haya novedades", "sub": "Noticias del lanzamiento y trastienda: solo unas pocas veces al mes."}}, "world": {"meta": {"title": "El mundo — Textopia", "desc": "Textopia, un continente donde la ropa respira y vive. Conoce sus seis tierras y las almas que las habitan."}, "hero": {"h1": "Un continente donde la ropa cobra vida", "sub": "Toca la tierra que te llame. Seis telas, seis historias.", "imgAlt": "Panorámica del continente de Textopia"}, "map": {"imgAlt": "Mapa del continente de Textopia", "svgAria": "Elige una región", "hint": "🪡 Toca la tierra que te llame"}, "panel": {"defaultName": "El continente de Textopia", "defaultTag": "Un mundo cosido con cuidado, puntada a puntada. Toca una tierra del mapa para empezar.", "cta": "Conoce este mundo en el capítulo 1 →"}, "regions": {"cotton": {"name": "Ciudad Algodón", "tag": "El corazón del continente. Una ciudad de humilde algodón, y hogar de la pequeña tienda de remiendos de Yiseo, Una Puntada.", "chips": ["Algodón y muselina", "Torre de la Aguja", "Tienda Una Puntada"], "meta": "<b>Habitantes</b> Gente de algodón, comerciantes del mercado<br><b>Lugares</b> Torre de la Aguja, el Mercado Central, tiendas de remiendo en los callejones<br><b>En una línea</b> La tela sencilla es la que más dura."}, "knit": {"name": "Montaña de Punto", "tag": "Cumbres nevadas tejidas con hilo. Sigue un hilo suelto y llegarás a la Rueda del Destino.", "chips": ["Punto y lana", "Rueda del Destino", "Paso del Hilo"], "meta": "<b>Habitantes</b> Cabras suéter, ancianos tejedores<br><b>Lugares</b> Rueda del Destino, el Muro de Hielo de Croché<br><b>En una línea</b> Lo que se deshace siempre se puede volver a tejer."}, "denim": {"name": "Cañón Denim", "tag": "Un cañón áspero con un corazón leal. La tribu Denim custodia el Lago Índigo.", "chips": ["Denim", "Lago Índigo", "Rocas Remache"], "meta": "<b>Habitantes</b> La tribu Denim, chaquetas lobo<br><b>Lugares</b> Lago Índigo, Cascada del Lavado<br><b>En una línea</b> Una tierra que solo se vuelve más bella con el uso."}, "silk": {"name": "Océano de Seda", "tag": "Un mar que cambia de color con la luz. Sobre él flota el Castillo Capullo.", "chips": ["Seda y chifón", "Castillo Capullo", "Isla del Botón de Perla"], "meta": "<b>Habitantes</b> Las casas de los Vestidos, bufandas mariposa<br><b>Lugares</b> Castillo Capullo, el Estrecho del Brillo<br><b>En una línea</b> La belleza nace de la suavidad."}, "leather": {"name": "Selva de Cuero", "tag": "Una selva dura y enmarañada en el sur. Solo la cruzan quienes atraviesan la Ciénaga del Curtido.", "chips": ["Cuero", "Ciénaga del Curtido", "Lianas de Hebilla"], "meta": "<b>Habitantes</b> Bestias con chaqueta de cuero, cazadores de botas<br><b>Lugares</b> Ciénaga del Curtido, los Acantilados de Tachas<br><b>En una línea</b> La armadura más dura es la que forja el tiempo."}, "grave": {"name": "Tumba de Harapos", "tag": "La última tierra donde reposa la ropa desechada. Donde esta historia empieza, y termina.", "chips": ["Trapos y harapos", "Ropa olvidada"], "meta": "<b>Habitantes</b> Ropa que ha perdido su nombre<br><b>Lugares</b> la Colina de las Tumbas de Botones<br><b>En una línea</b> Ser desechado no es lo mismo que estar acabado."}}, "dict": {"h2": "Un pequeño glosario ligero", "sub": "Sin spoilers: solo las claves para entender este mundo.", "grain": {"term": "Grano", "def": "El flujo único que lleva cada tela. Quienes saben leer el grano ven las heridas y los recuerdos de una prenda: el don que Yiseo despierta en este mundo."}, "mender": {"term": "Zurcidora", "def": "Quien remienda no solo el cuerpo de una prenda, sino también su corazón. El oficio más antiguo de Textopia, y uno que el mundo casi había olvidado."}, "ironStitch": {"term": "Puntada de Hierro", "def": "Una facción que cree que solo la ropa impecable tiene valor, y marca como 'defectuoso' todo lo que se sale de su norma."}, "needleTower": {"term": "Torre de la Aguja", "def": "La torre que se alza en el centro de Ciudad Algodón. Se dice que cada hilo del continente conduce hasta aquí."}, "wheelOfFate": {"term": "Rueda del Destino", "def": "Una gran rueda que gira en lo profundo de la Montaña de Punto, hilando el hilo del mundo."}, "raggedGrave": {"term": "Tumba de Harapos", "def": "La última tierra a la que llega la ropa desechada. Y, sin embargo, quizá no sea un final, sino un comienzo."}}, "chars": {"h2": "Las almas de este mundo", "sub": "Voltea una carta. Cada vuelta lleva la historia un poco más lejos.", "flipAria": "— toca para voltear la carta", "list": [{"name": "Yiseo", "role": "Zurcidora", "desc": "Dueña de una pequeña tienda de arreglos en Seúl, arrastrada a este mundo por un solo hilo. Sabe leer el grano de la tela."}, {"name": "Cassian", "role": "Caballero de Cuero", "desc": "Un antiguo caballero que permanece junto a Yiseo, luchando al lado de su traje de cuero, Bella."}, {"name": "Blue", "role": "Lobo de Denim", "desc": "Un fiel compañero de denim que cruza mundos junto a Yiseo."}, {"name": "Lily", "role": "Vestido de Chifón", "desc": "La primera clienta que visitó la tienda de remiendos, con una herida rasgada y tierna."}, {"name": "Bark", "role": "Chaqueta de Denim", "desc": "Un lobo del Cañón Denim. Áspero, pero cosido a base de lealtad."}, {"name": "Botón", "role": "Duende Botón", "desc": "El primer amigo y guía de Yiseo. Pequeño, pero el alma más firme de todas."}, {"name": "Noa", "role": "Sastre Aprendiz", "desc": "El primer alumno de Yiseo. Puntadas torpes, pero todas hechas con el corazón."}, {"name": "Satín", "role": "Casa de los Vestidos", "desc": "Una noble dama del Océano de Seda. Una historia escondida bajo el brillo."}, {"name": "Barón", "role": "???", "desc": "La sombra de la Torre de la Aguja. Aquel que predica la perfección."}, {"name": "Viejo Remiendo", "role": "Sabio de los Harapos", "desc": "El guardián de la Tumba de Harapos, que recuerda el nombre de cada cosa desechada."}]}}, "book": {"meta": {"title": "Los libros — Textopia", "desc": "La fantasía sanadora completa en tres volúmenes, 'Textopia'. Sinopsis, dónde comprarla y respuestas a las dudas más comunes."}, "hero": {"badge": "Fantasía sanadora · Trilogía completa", "title": "Textopia", "p1": "Una diminuta tienda de arreglos en un callejón de Seúl. La noche en que un aviso de remodelación urbana llega a sus manos, la zurcidora Yiseo sigue un solo hilo y cae en <b>Textopia, un mundo donde la ropa respira y vive.</b>", "p2": "Un vestido rasgado habla de sus heridas; una chaqueta gastada añora a quien la abandonó. Mientras la sombra de la Puntada de Hierro —que no exige más que ropa \"perfecta\"— se extiende por la tierra, Yiseo toma una sola aguja y empieza a remendar por igual la tela y el corazón. Una aventura tierna que da un segundo nombre a las cosas desechadas.", "buyBtn": "Comprar el libro electrónico"}, "vols": {"h2": "La trilogía completa", "v1": {"title": "Un destino que<br>no se remienda", "h3": "Volumen 1 (Partes 1–2)", "p": "Caída en un mundo extraño, Yiseo abre la puerta de su tienda de remiendos, 'Una Puntada'. Primeros clientes, primeros amigos, y una sombra que se reúne."}, "v2": {"title": "La sombra de la<br>Puntada de Hierro", "h3": "Volumen 2 (Partes 3–4)", "p": "El dominio de la 'perfección' se cierra sobre el continente. Junto a amigos de las seis tierras, Yiseo se acerca al secreto de la Torre de la Aguja."}, "v3": {"title": "La última<br>puntada", "h3": "Volumen 3 (Parte 5)", "p": "Comienza el remiendo más grande que el mundo haya conocido. En nombre de todo lo desechado: la última puntada."}}, "buy": {"h2": "Dónde comprar", "lead": "El libro electrónico está en camino. Cuando se abra, los lectores de nuestro boletín serán los primeros en saberlo.", "selfStore": "Nuestra propia tienda", "selfStoreDesc": "EPUB sin DRM · el mejor precio · el mayor apoyo para los autores", "storeBtn": "Ir a la tienda", "yesKyobo": "YES24 · Kyobo", "yesKyoboDesc": "En las apps de librería que ya conoces. Muy pronto.", "notifyBtn": "Avísame en el lanzamiento", "ridi": "RIDI", "ridiDesc": "Lee con comodidad en el visor de RIDI. Muy pronto.", "alert": "Esto se activará cuando el libro se lance. ¡Suscríbete a nuestro boletín!"}, "about": {"h2": "Dos personas fundamos una editorial. Tres, si cuentas a la IA.", "p1": "Una persona que antes escribía código (Taeha) conoció a una persona que antes confeccionaba ropa (Yeoreum). Construimos la historia juntas: una asienta sus huesos y sus sistemas, la otra le da vida con el tacto de la tela y con dibujos. Cuando nuestras manos no bastan, la IA presta unas cuantas más. Por eso somos pequeñas, pero nunca lentas.", "p2": "El 'margen de costura' es ese pequeño sobrante que dejas para rematar una prenda. Creemos que hasta la tela desechada, hasta las historias desechadas, llevan su propio margen de costura. Así fue como nuestra editorial encontró su nombre.", "imgAlt": "El taller de Seam Press"}, "news": {"h2": "Novedades", "item1": {"h3": "El libro electrónico de Textopia llega en el verano de 2026", "p": "Nos preparamos para publicar la trilogía completa de una sola vez. Sigue la trastienda en Instagram y en nuestro boletín."}}, "faq": {"h2": "Preguntas frecuentes", "q1": "¿Para quién es este libro?", "a1": "Para cualquiera que quiera escaparse a un mundo tierno al final de un día agotador. Aquí no hay crueldad: solo una historia de sanación y de vínculos.", "q2": "¿Habrá edición impresa?", "a2": "Primero lanzamos el libro electrónico y, según la respuesta, planeamos preparar una edición impresa mediante una campaña de crowdfunding en Tumblbug.", "q3": "¿Cómo leo el EPUB de tu propia tienda?", "a3": "Solo abre el archivo EPUB que recibes tras la compra en cualquier lector de EPUB: la app de RIDIBOOKS, Apple Books, Google Play Libros y más. Cada archivo lleva una discreta marca de agua con los datos del comprador.", "q4": "¿Hay planes para ediciones en el extranjero?", "a4": "Estamos trabajando en las traducciones al japonés y al inglés. Compartiremos las novedades a través de nuestro boletín."}}, "store": {"meta": {"title": "Tienda — Textopia", "desc": "El set completo de 3 libros de Textopia y los volúmenes sueltos en EPUB sin DRM. Descarga al instante tras la compra y lee en cualquier visor."}, "h1": "Tienda", "sub": "EPUB sin DRM. Descarga al instante y lee en cualquier visor.", "demoNote": "🧵 Por ahora esta es una <b>tienda de demostración</b>. No se procesan pagos reales: es una vista previa antes de nuestro lanzamiento oficial.", "popular": "Lo más popular", "set": {"cover": "Set completo<br>de 3 libros", "title": "Set completo de 3 libros de Textopia", "desc": "La historia entera, de principio a fin. 25 % de descuento frente a los volúmenes sueltos, más una nota especial de los autores.", "priceLabel": "Precio del set", "buy": "Comprar el set"}, "vol1": {"cover": "Un destino que va<br>más allá del remiendo", "name": "Libro 1 (volumen suelto)", "desc": "Donde todo comienza: un mundo extraño y la primera puntada.", "buy": "Comprar el Libro 1"}, "singleLabel": "Precio suelto", "vol23": {"cover": "La historia<br>continúa", "name": "Libros 2 y 3 (volúmenes sueltos)", "desc": "₩4,500 cada uno. Empieza primero por el Libro 1.", "priceEach": "₩4,500 cada uno", "buy": "Comprar"}, "guide": {"h2": "Información de compra", "include": "Qué incluye", "includeBody": "Archivo EPUB (con marca de agua del comprador), nota de los autores y actualizaciones gratuitas (ediciones con erratas corregidas). Con el set, un extra especial.", "download": "Cómo descargar", "downloadBody": "Tras el pago, se envía un enlace de descarga a tu correo. El enlace puede usarse hasta 3 veces dentro de 24 horas. Si caduca, puedes solicitar uno nuevo.", "refund": "Política de reembolso", "refundBody": "Al tratarse de un producto digital, el reembolso completo está disponible antes de la descarga; después de descargar, no es posible reembolsar. Prueba el capítulo 1 gratis para estar segura antes de decidir."}}, "quiz": {"meta": {"title": "Encuentra tu prenda compañera — Textopia", "desc": "En el mundo de Textopia, ¿qué prenda está destinada a caminar a tu lado? Un test de un minuto."}, "questions": [{"q": "Al final de un día largo y agotador, lo primero que haces al llegar a casa es…", "options": ["Meterte directo bajo las mantas acogedoras", "Contarle a alguien, con calma, todo tu día", "Dejar preparada la ropa de mañana", "Salir de repente por un antojo de medianoche"]}, {"q": "Una amiga te llama llorando. Tus primeras palabras son…", "options": ["Tranquila, tómate tu tiempo y cuéntame.", "¿Dónde estás? Voy para allá.", "Antes que nada, ¿has comido algo?", "Vamos a ordenar con calma lo que pasó."]}, {"q": "Cuando abres el armario, la prenda a la que más va tu mano es…", "options": ["Esa que llevas diez años y que nunca te cansa", "Un conjunto deslumbrante que te levanta el ánimo del día", "Algo familiar y cómodo que te abraza", "Una prenda marcada y con estructura, con un poco de carácter"]}, {"q": "Has llegado a una ciudad desconocida. Tu estilo de viajar es…", "options": ["Puntual con el plan: lo ves todo", "Tres horas en una tienda que encontraste de casualidad en un callejón", "Directo a los rincones que solo conocen los locales", "Instalada con elegancia en el café con las mejores vistas"]}, {"q": "Si alguien te describiera con una sola palabra, la que más te gustaría es…", "options": ["De fiar", "De buen corazón", "Con estilo", "De voluntad firme"]}, {"q": "Has caído en Textopia. El primer lugar que quieres visitar es…", "options": ["La Montaña de Punto, donde el hilo canta", "El Océano de Seda, que brilla con la luz", "El Cañón Denim, áspero y libre", "'Una Puntada', la vieja tienda de remiendos del callejón"]}], "results": {"denim": {"name": "Chaqueta de Denim · Blue", "sub": "DENIM — La compañera leal", "desc": "De las que solo se ven más impactantes con el uso. Una vez que dejas entrar a alguien, lo acompañas hasta el final. Puedes parecer áspera, pero cuando todo se derrumba siempre eres la primera en acudir corriendo.", "mate": "Blue, el lobo del Cañón Denim", "spot": "Cañón Denim · Lago Índigo"}, "chiffon": {"name": "Vestido de Chifón · Lily", "sub": "CHIFÓN — La compañera empática", "desc": "En lugar de doblarte con el viento, escuchas las historias que el viento trae. Tu suavidad no es debilidad: es una sensibilidad que otros sencillamente no tienen.", "mate": "El vestido de Lily, la primerísima clienta de la tienda de remiendos", "spot": "Ciudad Algodón · la tienda de remiendos del callejón"}, "knit": {"name": "Suéter de Punto", "sub": "PUNTO — La compañera del calor", "desc": "Contigo cerca, hasta el invierno se hace llevadero. Prefieres dar calor durante mucho tiempo antes que deslumbrar un instante. Eres de las que saben que todo lo que se deshace siempre se puede volver a tejer.", "mate": "El hilo de la Rueda del Destino", "spot": "Montaña de Punto · la Rueda de Agua"}, "leather": {"name": "Chaqueta de Cuero", "sub": "CUERO — La compañera inquebrantable", "desc": "De las que solo se vuelven más geniales con el tiempo. Hasta las heridas y las cicatrices se convierten en parte de tu estampado. Diga lo que diga el mundo, tienes el temple de vivir según tu propio grano.", "mate": "La chaqueta errante de la Selva de Cuero", "spot": "Selva de Cuero · Acantilados de Tachas"}, "silk": {"name": "Bufanda de Seda", "sub": "SEDA — La compañera elegante", "desc": "De las que muestran un color distinto con cada luz. Sabes que la belleza no es un lujo, sino una forma de vivir, y que la suavidad vence a la fuerza.", "mate": "La bufanda del Castillo Capullo", "spot": "Océano de Seda · el Estrecho del Brillo"}, "linen": {"name": "Delantal de Muselina · el de Yiseo", "sub": "LINO — La compañera constante", "desc": "La tela más sencilla es la que más dura. Puntada a puntada, día tras día, eres quien acaba remendando el mundo entero. Esta es precisamente la tela que Yiseo, nuestra heroína, eligió para sí misma.", "mate": "El delantal de trabajo de la zurcidora Yiseo", "spot": "Ciudad Algodón · la tienda 'Una Puntada'"}}, "ui": {"mateLabel": "Tu compañero del destino", "spotLabel": "Tu tierra", "share": "Compartir mi resultado", "readCta": "Conoce este mundo en el capítulo 1", "retry": "Intentar de nuevo", "shareTitle": "Encuentra tu prenda compañera", "shareLine": "Mi prenda compañera de Textopia es [{name}] — {sub}", "shareHook": "Encuentra la tuya también: https://textopia.vercel.app/quiz.html", "copied": "¡Resultado copiado! Pégalo para enviárselo a una amiga."}}, "read": {"meta": {"title": "Lee el capítulo 1 gratis — Textopia", "desc": "Lee gratis el capítulo 1 de Textopia, una acogedora fantasía sanadora en la que Yiseo, una zurcidora, oye hablar a la ropa por primera vez. (El capítulo está actualmente en coreano.)"}, "nav": {"exit": "Salir", "pos": "Textopia · Libro 1, Cap. 1"}, "settings": {"open": "Ajustes de lectura", "size": "Tamaño del texto", "sizeS": "Pequeño", "sizeM": "Predeterminado", "sizeL": "Grande", "sizeXL": "Más grande", "bg": "Fondo", "light": "Claro", "sepia": "Sepia", "dark": "Oscuro"}, "end": {"title": "Has atado tu primer nudo", "teaserLabel": "Avance del capítulo 2", "next": "Sigue leyendo la próxima historia", "world": "Explora más de este mundo"}}, "terms": {"meta": {"title": "Términos de uso — Textopia", "desc": "Los Términos de uso de Textopia, operado por Orsion (marca: Seam Press): las condiciones para usar nuestros servicios de lectura de contenidos y venta de libros electrónicos."}, "h1": "Términos de uso", "updated": "Fecha de entrada en vigor: 12 de julio de 2026 · Orsion (marca: Seam Press)", "s1": {"h": "Artículo 1 (Objeto)", "body": "Estos términos establecen las condiciones para usar los servicios de lectura de contenidos y venta de libros electrónicos ofrecidos en el sitio web de Textopia (el \"Sitio\"), operado por Orsion (la \"Empresa\")."}, "s2": {"h": "Artículo 2 (Servicios)", "body": "① Acceso gratuito al capítulo 1 de la novela \"Textopia\", información sobre el mundo de la obra y envío del boletín<br>② Venta y descarga de libros electrónicos (EPUB): hasta el lanzamiento oficial, la función de pago se muestra como demostración y no se procesa ningún pago real."}, "s3": {"h": "Artículo 3 (Derechos de autor)", "body": "Los derechos de autor de todo el contenido del Sitio (el texto de la novela, el mundo de la obra, las ilustraciones y el diseño) pertenecen a la Empresa. Los libros electrónicos comprados solo pueden usarse para conservación y lectura personales; la reproducción, distribución o difusión no autorizadas pueden acarrear responsabilidad conforme a la ley de derechos de autor. Los archivos de los libros electrónicos incluyen una marca de agua que identifica al comprador."}, "s4": {"h": "Artículo 4 (Compra, descarga y reembolsos)", "body": "① Una vez completado el pago, se envía un enlace de descarga a la dirección de correo que hayas indicado (válido para 3 usos dentro de 24 horas; reemitible tras la caducidad).<br>② Dada la naturaleza del contenido digital, <b>el reembolso completo está disponible antes de la descarga</b>, mientras que después de la descarga el reembolso resulta difícil, salvo cuando el contenido sea defectuoso (Artículo 17, apartado 2, de la Ley de Protección al Consumidor en el Comercio Electrónico).<br>③ Si un archivo es defectuoso o falta, lo volveremos a proporcionar sin costo o emitiremos un reembolso completo."}, "s5": {"h": "Artículo 5 (Boletín)", "body": "La suscripción es gratuita y puede cancelarse en cualquier momento. Cuando la Empresa envíe información promocional, lo indicará en el asunto del mensaje."}, "s6": {"h": "Artículo 6 (Exención de responsabilidad)", "body": "La Empresa no se hace responsable de las interrupciones del servicio causadas por fuerza mayor, como desastres naturales o fallos del servicio en la nube. No obstante, los derechos de descarga de los compradores de pago quedan garantizados una vez restablecido el servicio."}, "s7": {"h": "Artículo 7 (Resolución de conflictos)", "body": "Los conflictos relacionados con el uso del servicio se resolverán mediante consulta de buena fe entre la Empresa y el usuario; cuando la consulta resulte difícil, podrá presentarse una demanda ante el tribunal competente conforme a la Ley de Enjuiciamiento Civil. Contacto: <a class=\"stitch-link\" href=\"mailto:neocomix@neocomix.com\">neocomix@neocomix.com</a>"}}, "privacy": {"meta": {"title": "Política de privacidad — Textopia", "desc": "La Política de privacidad de Textopia por Orsion (marca: Seam Press). Conoce qué datos personales recopilamos, por qué, cuánto tiempo los conservamos, nuestros encargados de tratamiento y tus derechos."}, "h1": "Política de privacidad", "updated": "En vigor: 12 de julio de 2026 · Orsion (marca: Seam Press)", "s1": {"h": "1. Datos personales que recopilamos y por qué", "body": "Orsion (\"la Empresa\") recopila únicamente la siguiente información en el sitio web de Textopia.", "list": "① <b>Suscripción al boletín</b>: dirección de correo electrónico, para enviar noticias de publicación y novedades de la trastienda<br>② <b>Compras de libros electrónicos (muy pronto)</b>: dirección de correo electrónico, registros de pago, para entregar los productos (envío de enlaces de descarga) y procesar reembolsos<br>③ <b>Mejora del servicio</b>: registros de uso no identificativos, como visitas y clics (no se usan cookies; no es posible identificar a las personas)"}, "s2": {"h": "2. Periodo de conservación y uso", "body": "Las direcciones de correo del boletín se <b>destruyen de inmediato al cancelar la suscripción</b>. Los registros de compra se conservan durante 5 años conforme a la Ley de Protección al Consumidor en el Comercio Electrónico, y luego se destruyen."}, "s3": {"h": "3. Encargo del tratamiento y lugar de almacenamiento", "body": "La información recopilada se almacena mediante una conexión cifrada en la base de datos en la nube que utiliza la Empresa (Supabase Inc., región de Seúl). La Empresa no proporciona ni vende datos personales a ningún tercero por ningún otro medio."}, "s4": {"h": "4. Tus derechos", "body": "Puedes solicitar en cualquier momento el acceso, la corrección, la eliminación o la suspensión del tratamiento de tus datos personales. Puedes cancelar la suscripción al boletín mediante el enlace de baja al pie de cada correo o a través del contacto indicado abajo, y tales solicitudes se atienden sin demora."}, "s5": {"h": "5. Responsable de protección de datos", "body": "Nombre: Kwon Taek-jun (CEO) · Correo: <a class=\"stitch-link\" href=\"mailto:neocomix@neocomix.com\">neocomix@neocomix.com</a><br>Consultas sobre vulneración de la privacidad: Centro de Denuncias de Privacidad de la Agencia de Internet y Seguridad de Corea (privacy.kisa.or.kr, marca el 118 sin prefijo)"}, "s6": {"h": "6. Deber de notificación", "body": "Si esta política se modifica, lo notificaremos a través de los anuncios del sitio web 7 días antes de su entrada en vigor."}, "footer": {"body": "Orsion · CEO Kwon Taek-jun · Reg. mercantil n.º 609-35-66228 · Contacto neocomix@neocomix.com<br><a class=\"stitch-link\" href=\"terms.html\">Términos de uso</a> · <a class=\"stitch-link\" href=\"index.html\">Inicio</a><br>© 2026 Orsion."}}, "checkout": {"meta": {"title": "Pago — Textopia", "desc": "Consigue el set completo de 3 volúmenes de Textopia en EPUB sin DRM. Solo introduce tu correo y te enviaremos el enlace de descarga. (Pago de demostración: sin cobro real.)"}, "h1": "Tu pedido", "sub": "Lo único que necesitamos es el correo al que debe llegar tu enlace de descarga del EPUB.", "demoNote": "🧵 Este es un pago de demostración. No recopilamos datos de tarjeta y no se realiza ningún cobro real.", "steps": {"order": "Pedido", "pay": "Pago", "done": "Listo"}, "price": {"disc": "Descuento", "total": "Total"}, "field": {"emailLabel": "Correo (para tu enlace de descarga)", "emailPh": "tu@ejemplo.com", "emailHint": "Por favor, revisa el formato de tu correo"}, "agree": {"item1": "Entiendo que es un producto digital (sin reembolsos tras la descarga). (Obligatorio)", "item2": "Envíame también el boletín con las noticias del lanzamiento. (Opcional)"}, "pay": "Pagar ahora (Demo)", "msg": {"paying": "Enhebrando la aguja…"}, "items": {"set": ["Textopia — Set completo de 3 volúmenes (EPUB)", "₩9,900", "-₩3,600", "₩9,900"], "vol1": ["Textopia Vol. 1 — Un destino que va más allá del remiendo (EPUB)", "₩4,500", "₩0", "₩4,500"], "vol2": ["Textopia Vol. 2 — La sombra de la Puntada de Hierro (EPUB)", "₩4,500", "₩0", "₩4,500"]}}, "success": {"meta": {"title": "Pedido completado — Textopia", "desc": "Tu pedido está completo. Enviaremos el enlace de descarga al correo que introdujiste. (Confirmación de pedido de demostración.)"}, "steps": {"order": "Pedido", "pay": "Pago", "done": "Listo"}, "h1": "El nudo está atado", "msg": "Enviaremos tu enlace de descarga al correo que introdujiste.<br>(Es una demostración, así que no se envía ningún correo real.)", "item": {"set": "Textopia: Set completo de 3 libros (EPUB)", "vol1": "Textopia Libro 1 (EPUB)", "vol2": "Textopia Libro 2 (EPUB)"}, "itemNote": "Enlace de descarga válido durante 24 horas / 3 descargas tras el envío.<br>Se abre en cualquier lector de EPUB (Ridi, Apple Books, Play Libros y más).", "reread": "Relee el capítulo 1 mientras esperas", "home": "Volver al inicio"}};

